async function loadSiteData(){try{const e=await fetch("data/site.json",{cache:"no-cache"});if(!e.ok)throw new Error(`HTTP ${e.status}`);return await e.json()}catch(e){return console.warn("Failed to load site data:",e),null}}function createPropertyCard(e){const a=document.createElement("div");a.className="property-masterpiece",a.setAttribute("data-aos","fade-up"),"number"==typeof e.aosDelay&&a.setAttribute("data-aos-delay",String(e.aosDelay));const t=e.badgeClass?`property-badge ${e.badgeClass}`:"property-badge",n=(e.features||[]).map(e=>`\n            <div class="feature-item">\n                <i class="${e.icon}"></i>\n                <span>${e.text}</span>\n            </div>\n        `).join("");return a.innerHTML=`\n        <div class="property-visual">\n            <div class="property-image">\n                <img src="${e.image}" alt="${e.imageAlt||e.title}" loading="lazy">\n                <div class="image-overlay"></div>\n            </div>\n            <div class="${t}">${e.badgeText||""}</div>\n            <div class="property-hover-content">\n                <button class="explore-btn">EXPLORE DETAILS</button>\n            </div>\n        </div>\n        <div class="property-details">\n            <div class="property-header">\n                <h3>${e.title}</h3>\n                <div class="property-rating">\n                    <i class="fas fa-star"></i>\n                    <i class="fas fa-star"></i>\n                    <i class="fas fa-star"></i>\n                    <i class="fas fa-star"></i>\n                    <i class="fas fa-star"></i>\n                </div>\n            </div>\n            <p class="property-description">\n                ${e.description||""}\n            </p>\n            <div class="property-features">\n                ${n}\n            </div>\n            <div class="property-pricing">\n                <div class="price-main">${e.priceMain||""}</div>\n                <div class="price-note">${e.priceNote||""}</div>\n            </div>\n        </div>\n    `,a}function renderProperties(e){const a=document.querySelector('[data-module="properties"]');a&&e?.properties?.length&&(a.innerHTML="",e.properties.forEach(e=>a.appendChild(createPropertyCard(e))))}function createGalleryFilters(e){const a=document.createElement("div");return a.className="gallery-filters",(e||[]).forEach(e=>{const t=document.createElement("button");t.className="filter-pill"+("all"===e.key?" active":""),t.type="button",t.setAttribute("data-filter",e.key),t.innerHTML=`${e.icon?`<i class="${e.icon}"></i>`:""}${e.label}`,a.appendChild(t)}),a}function createGalleryPiece(e){const a=document.createElement("div");return a.className="gallery-piece",a.setAttribute("data-category",e.category||"all"),a.innerHTML=`\n        <div class="piece-image">\n            <img src="${e.image}" alt="${e.imageAlt||e.title}" loading="lazy">\n        </div>\n        <div class="piece-overlay">\n            <div class="piece-info">\n                <div class="piece-category">${(e.category||"").toUpperCase()}</div>\n                <h4>${e.title||""}</h4>\n                <p>${e.subtitle||""}</p>\n            </div>\n        </div>\n    `,a}function renderGallery(e){const a=document.querySelector('[data-module="gallery"]');if(!a)return;if(!e?.gallery?.items?.length)return;a.innerHTML="";const t=e.gallery.filters?.length?e.gallery.filters:[{key:"all",label:"All"}];a.appendChild(createGalleryFilters(t));const n=document.createElement("div");n.className="gallery-grid",e.gallery.items.forEach(e=>n.appendChild(createGalleryPiece(e))),a.appendChild(n)}window.__modulesReady=(async()=>{const e=await loadSiteData();renderProperties(e),renderGallery(e)})();